var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아, 멈춰.","JPN":"レヴィア、待て。","ENG":"Levia, stop!","TWN":"莉維亞，停下來。"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"왜요? 설마 유리 언니 있는 데로 돌아가자고 하게요?","JPN":"何ですか？　まさかユリさんのところに戻ろうとでもいうつもりですか？","ENG":"Why? You're not thinking of heading back for Yuri, are you?","TWN":"幹嘛？不會是要回去找悠麗姊姊吧？"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하여간 눈치는 빠르군. 이유리가 네 반이라도 닮으면 좋았을 텐데.","JPN":"まったく、勘がいいな。カスカベがお前に半分でも似てくれたら助かるんだが。","ENG":"Guess you're not as slow as I thought. If only Yuri could catch on half as fast as you.","TWN":"反應還真快，真希望李悠麗有你一半聰明就好。"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"녀석이 아니면 베로니카를 상대할 수가 없어. 반드시 데리고 가야 한다.","JPN":"あいつじゃないとベロニカの相手は無理だ。必ず連れて帰らなければ。","ENG":"She's the only one who can go against Veronica. We need to take her with us.","TWN":"要是沒那傢伙，我們是打不贏貝洛妮卡的，一定要帶上她。"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이, 짠한 동료애를 기대했는데 삭막한 말씀을 하시네.","JPN":"もう、涙ぐましい仲間意識を期待してたのにドライなんですね。","ENG":"Oof, and here I was hoping you'd say something about comradery.","TWN":"哎呀，我還期待有灑狗血的同胞愛呢，結果還真冷漠。"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"겸사겸사야. 정에 매여선 이 짓도 오래 못 해.","JPN":"ついでだ。情にかまけているとこの仕事も長くはやれない。","ENG":"A little bit of both, okay? But you won't last long in this industry if you cling onto feelings.","TWN":"差不多就好，放太多感情是沒辦法幹這行的。"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"좋아요. 대신 창자에 구멍 나도 제 탓 하기 없기예요?","JPN":"いいですよ。その代わりに、お腹に穴が開いても私を責めないでくださいね？","ENG":"Okay! But don't blame me if you end up getting a hole in your stomach.","TWN":"好吧，不過到時候你腸子破洞可別怪我喔！"},"stage":{"bg":"BACKSTREET2","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이제 그만 포기하시지? 아직도 상황 파악이 안 돼?","JPN":"もうあきらめたら？　まだ状況が把握できないの？","ENG":"Give up already! Can't you see you lost?","TWN":"放棄吧？你還搞不清楚狀況嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 데 쓸 주변머리는 옛날에 다 갖다 버렸어. 잡아 족쳐야 할 괴물들이 한둘이어야지.","JPN":"そういう場合の要領の良さは遥か昔に捨てた。捕まえて殺すべき化け物が多すぎてね。","ENG":"I threw that kind of attitude away a long time ago. You see, there are too many monsters in this world that need killing.","TWN":"我從很久以前就已經扔掉這種變通的能力，畢竟要對付的怪物太多。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우린 그쪽이 해야 할 일을 대신 해 주고 있는 거야. 감사하는 시늉이라도 하지 그래.","JPN":"私たちは本来ならあなたたちがやるべき仕事を代わりにやってあげてるんだ。感謝してほしいな。","ENG":"You know, we're basically doing your job for you! Shouldn't you be thanking us?","TWN":"我們是在幫你們做你們該做的事，好歹也假裝感謝一下吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기들 멋대로 법을 무시하고 다니면서 말이야?","JPN":"自分勝手に法を無視して？","ENG":"For what? Running around and disobeying the law?","TWN":"你們藐視法律還要我們表示感謝嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"애초에 그딴 식으로 도와달라고 한 적도 없어!","JPN":"そもそもそんな風に助けてくれなんて頼んだ覚えもない！","ENG":"Also, we never asked for your help!","TWN":"我們從未拜託你們用這種方式幫忙過！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 조심하세요! 공범들이 주위에 남아 있을지도 몰라요!","JPN":"警視様、気をつけてください！　共犯者がこの辺りに残ってるかもしれません！","ENG":"Major, watch out! Her accomplices might be lurking nearby!","TWN":"警正，小心！周圍可能還有共犯！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아니! 이건 공권력의 위신이 걸린 문제야! 강소영 경위!","JPN":"いいえ！　これは公権力の威信にかかわる問題よ！　マエカワ警部補！","ENG":"No, Lieutenant Kang! This is a matter of preserving public authority!","TWN":"不！這可是攸關公權力威信的問題！姜素英員警！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아아, 결국 또 뻔한 도발에 넘어가 버리시네……","JPN":"ああ、結局またあからさまな挑発に乗せられて……","ENG":"Ugh... There she goes taking the bait again...","TWN":"哀哀，又落入對方激將法的圈套裡……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":" 응?","JPN":" んっ？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐야, 경위?! 방해되니까 저리 비켜!","JPN":"何よ、警部補！？　邪魔だからどきなさい！","ENG":"What are you doing, Lieutenant?! Get out of my way!","TWN":"你幹嘛，姜素英員警？！別妨礙我，走開！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저격이에요, 경정님! 숙이세요!","JPN":"狙撃です、警視様！　伏せて！","ENG":"There's a sniper, Major! Duck!","TWN":"警正！有狙擊，低頭！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"唔……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"겨, 경위? 강소영 경위?","JPN":"け、警部補？　マエカワ警部補？","ENG":"L-lieutenant? Lieutenant Kang!!","TWN":"姜…姜素英員警？姜素英員警？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"현장에서 장난치지 말라고 했잖아. 나도 이제 무능력자라고 안 부르니까……","JPN":"現場でふざけないでって言ったでしょ。もう無能力者なんて呼ばないから……","ENG":"I thought I told you to stop kidding around on the scene. Here, I won't call you incompetent anymore, so...","TWN":"我不是說過別在執行任務時開玩笑嗎？我不會再叫你無能者……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"피가……. 피……. 너무, 많이 흐르는데…….","JPN":"血が……血……流しすぎ、なんだけど……","ENG":"B-blood... She's losing too much of it...!","TWN":"血……血……好多血……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"카…… 카운터도 아니면서, 이렇게 다치면 위험한 거 몰라?","JPN":"か……カウンターでもないのに、こんな怪我したら死ぬってわかってるでしょ？","ENG":"You... You're not even a Counter... Don't you know how dangerous it is for you out here?","TWN":"你……你又不是制裁者，不知道受這麼嚴重的傷會有生命危險嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위, 대답해.","JPN":"警部補、答えなさいよ。","ENG":"Answer me, Lieutenant.","TWN":"姜素英員警，回答我！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"상관이 부르면 대답하라고……!","JPN":"上官が呼んだら返事しなさいよ……！","ENG":"Answer when your boss calls...!","TWN":"上司在跟你說話，快回答我……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을, 저 멍청한 녀석…….","JPN":"くそ、あのバカが……","ENG":"Crap. That fool...","TWN":"該死，那個傻瓜……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지금이다, 이유리. 어서 현장에서 철수해.","JPN":"今だ、カスカベ。急いで現場から撤収しろ。","ENG":"Now, Yuri! Get out of there!","TWN":"趁現在，李悠麗，快逃！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장……. 방금 그거 대장이 쏜 거야?","JPN":"隊長……さっきの、隊長が撃ったの？","ENG":"Captain... Was that your doing?","TWN":"隊長……剛才是你開的槍嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 부축을 받느라 조준이 조금 틀어지긴 했지만…… 소기의 목적은 달성한 것 같다.","JPN":"ああ。支えてもらってるから照準が少しブレたが……目的は達成したようだ。","ENG":"Yeah. My aim was a bit off because I needed some help from Levia... But either way, I got what I wanted.","TWN":"嗯嗯，但是因為被攙扶著有點射偏……不過應該有達到預期的目標。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"상대는 경찰이야! 건드렸다가 일 커지는 거 몰라? 대장까지 왜 그래?!","JPN":"相手は警察だよ！　手を出したら大変なことになる！　隊長までどうして！？","ENG":"But they're cops! Killing one of them will only make things more complicated! You know that!","TWN":"對方可是警察！你不知道這樣會把事情鬧大嗎？為什麼連你也這樣？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리가 하려던 일을 마저 끝내야지.","JPN":"やりかけた仕事を終わらせるためだ。","ENG":"We still have a job to do.","TWN":"我們還有任務要完成。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만, 나는 역시 그 여자가…….","JPN":"でも、私はやっぱりあの女が……","ENG":"But... I'm worried that she...","TWN":"可是我擔心她……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……애초에 노린 건 그 녀석이 아니었다. 자기가 죽을 곳으로 뛰어들었을 뿐이야.","JPN":"……そもそも狙ったのはあいつではなかった。自ら死地に飛び込んだんだ。","ENG":"I wasn't aiming for her. And she's the one who stepped into the crossfire.","TWN":"……我一開始就不是瞄準她，是她自己要衝出來受死的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자. 움직여, 어서.","JPN":"さあ。動け、早く。","ENG":"Now, get out of there while you can.","TWN":"快點離開！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위! 정신 차려! 눈 좀 떠 보라고!! 대체 왜 이러는 거야!! 왜!!","JPN":"警部補！　しっかりしなさい！　目を開けなさい！！　いったい何なの！！　なんで！！","ENG":"Lieutenant! Wake up! That's an order!! Why won't you open your eyes?! WHY?!","TWN":"姜素英員警！你醒醒！你睜開眼睛！！你為什麼都不說話！！為什麼！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영!!","JPN":"マエカワ・ナツミ！！","ENG":"Kang Soyoung!!","TWN":"姜素英！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};